// Solution
class Calculator<T> {
  add(x: T, y: T): T {
    return x + y;
  }
  subtract(x: T, y: T): T {
    return x - y;
  }
  multiply(x: T, y: T): T {
    return x * y;
  }
  divide(x: T, y: T): T {
    return x / y;
  }
  lastOperation(): T {
    if (this.result !== undefined) {
      return this.result as T;
    } else {
      throw new Error('No operation performed yet');
    }
  }

  result: T | undefined;
}

