class Calculator:
  def __init__(self):
    self.result = None
  def add(self, x, y):
    self.result = x + y
    return self.result
  def subtract(self, x, y):
    self.result = x - y
    return self.result
  def multiply(self, x, y):
    self.result = x * y
    return self.result
  def divide(self, x, y):
    self.result = x / y
    return self.result
  def lastOperation(self):
    if self.result is not None:
      return self.result
    else:
      raise ValueError('No operation performed yet')
